// loadSessionFromDisk loads and validates a session from disk.
func (sm *SessionManager) loadSessionFromDisk(sessionID string) (*Session, error) {
	if err := validateSessionID(sessionID); err != nil {
		return nil, err
	}

	sessionPath, err := sm.sessionFilePath(sessionID)
	if err != nil {
		return nil, err
	}
	hmacPath, err := sm.hmacFilePath(sessionID)
	if err != nil {
		return nil, err
	}

	// Read session data
	data, err := os.ReadFile(sessionPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read session file: %w", err)
	}

	// Enforce maximum session file size before processing
	const maxSessionSize = 64 * 1024
	if len(data) > maxSessionSize {
		os.Remove(sessionPath)
		os.Remove(hmacPath)
		return nil, errors.New("session file too large, possibly tampered")
	}

	// Read and verify HMAC BEFORE deserialization
	storedMAC, err := os.ReadFile(hmacPath)
	if err != nil {
		os.Remove(sessionPath)
		return nil, fmt.Errorf("failed to read HMAC file (possible tampering): %w", err)
	}

	if !verifyHMAC(data, storedMAC) {
		// HMAC mismatch - data has been tampered with. Do NOT deserialize.
		os.Remove(sessionPath)
		os.Remove(hmacPath)
		return nil, errors.New("session integrity check failed: possible tampering detected")
	}

	// Only deserialize after HMAC verification passes
	session := &Session{}
	reader := io.LimitReader(strings.NewReader(string(data)), maxSessionSize)
	decoder := gob.NewDecoder(reader)
	if err := decoder.Decode(session); err != nil {
		os.Remove(sessionPath)
		os.Remove(hmacPath)
		return nil, fmt.Errorf("failed to decode session: %w", err)
	}

	// Deep validation of deserialized data
	if err := sm.validateSession(session); err != nil {
		os.Remove(sessionPath)
		os.Remove(hmacPath)
		return nil, fmt.Errorf("loaded session failed validation: %w", err)
	}

	// Verify the session ID in the file matches the filename
	if session.ID != sessionID {
		os.Remove(sessionPath)
		os.Remove(hmacPath)
		return nil, errors.New("session ID mismatch")
	}

	return session, nil
}

// loadAllSessions loads all valid sessions from disk.
func (sm *SessionManager) loadAllSessions() error {
	entries, err := os.ReadDir(sm.storageDir)
	if err != nil {
		return fmt.Errorf("failed to read storage directory: %w", err)
	}

	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}

		name := entry.Name()
		if !strings.HasSuffix(name, ".session") {
			continue
		}

		sessionID := strings.TrimSuffix(name, ".session")
		if err := validateSessionID(sessionID); err != nil {
			// Skip invalid session files
			continue
		}

		session, err := sm.loadSessionFromDisk(sessionID)
		if err != nil {
			fmt.Printf("Warning: skipping invalid session %s: %v\n", sessionID, err)
			continue
		}

		sm.sessions[sessionID] = session
	}

	return nil
}

// CleanExpiredSessions removes expired sessions.
func (sm *SessionManager) CleanExpiredSessions() int {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	now := time.Now()
	removed := 0

	for id, session := range sm.sessions {
		if now.After(session.ExpiresAt) {
			delete(sm.sessions, id)

			sessionPath, err := sm.sessionFilePath(id)
			if err == nil {
				os.Remove(sessionPath)
			}
			hmacPath, err := sm.hmacFilePath(id)
			if err == nil {
				os.Remove(hmacPath)
			}

			removed++
		}
	}

	return removed
}

// HTTP Handlers

func (sm *SessionManager) handleCreateSession(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	userID := r.FormValue("user_id")
	if userID == "" {
		http.Error(w, "user_id required", http.StatusBadRequest)
		return
	}

	preferences := map[string]string{
		"theme":    r.FormValue("theme"),
		"language": r.FormValue("language"),
		"timezone": r.FormValue("timezone"),
	}

	// Remove empty preferences
	for k, v := range preferences {
		if v == "" {
			delete(preferences, k)
		}
	}

	// Set defaults
	if _, ok := preferences["theme"]; !ok {
		preferences["theme"] = "light"
	}
	if _, ok := preferences["language"]; !ok {
		preferences["language"] = "en"
	}

	permStr := r.FormValue("permissions")
	var permissions []string
	if permStr != "" {
		permissions = strings.Split(permStr, ",")
		for i := range permissions {
			permissions[i] = strings.TrimSpace(permissions[i])
		}
	} else {
		permissions = []string{"read"}
	}

	session, err := sm.CreateSession(userID, preferences, permissions)
	if err != nil {
		http.Error(w, "Failed to create session: "+err.Error(), http.StatusBadRequest)
		return
	}

	// Set session cookie (HttpOnly, Secure, SameSite)
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    session.ID,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   int(sm.sessionTTL.Seconds()),
	})

	fmt.Fprintf(w, "Session created: %s for user %s\n", session.ID, session.UserID)
}

func (sm *SessionManager) handleGetSession(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	session, err := sm.GetSession(cookie.Value)
	if err != nil {
		http.Error(w, "Session error: "+err.Error(), http.StatusUnauthorized)
		return
	}

	fmt.Fprintf(w, "Session ID: %s\n", session.ID)
	fmt.Fprintf(w, "User ID: %s\n", session.UserID)
	fmt.Fprintf(w, "Created: %s\n", session.CreatedAt.Format(time.RFC3339))
	fmt.Fprintf(w, "Expires: %s\n", session.ExpiresAt.Format(time.RFC3339))
	fmt.Fprintf(w, "Preferences:\n")
	for k, v := range session.Preferences {
		fmt.Fprintf(w, "  %s: %s\n", k, v)
	}
	fmt.Fprintf(w, "Permissions: %s\n", strings.Join(session.Permissions, ", "))
}

func (sm *SessionManager) handleUpdatePreferences(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	preferences := make(map[string]string)
	for key := range validPreferenceKeys {
		val := r.FormValue(key)
		if val != "" {
			preferences[key] = val
		}
	}

	if len(preferences) == 0 {
		http.Error(w, "No valid preferences provided", http.StatusBadRequest)
		return
	}

	if err := sm.UpdatePreferences(cookie.Value, preferences); err != nil {
		http.Error(w, "Failed to update: "+err.Error(), http.StatusBadRequest)
		return
	}

	fmt.Fprintf(w, "Preferences updated\n")
}

func (sm *SessionManager) handleDeleteSession(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	cookie, err := r.Cookie("session_id")
	if err != nil {
		http.Error(w, "No session cookie", http.StatusUnauthorized)
		return
	}

	if err := sm.DeleteSession(cookie.Value); err != nil {
		http.Error(w, "Failed to delete: "+err.Error(), http.StatusBadRequest)
		return
	}

	// Clear cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   -1,
	})

	fmt.Fprintf(w, "Session deleted\n")
}

func main() {
	sm, err := NewSessionManager("./sessions")
	if err != nil {
		fmt.Printf("Failed to initialize session manager: %v\n", err)
		os.Exit(1)
	}

	// Start background cleanup goroutine
	go func() {
		ticker := time.NewTicker(5 * time.Minute)
		defer ticker.Stop()
		for range ticker.C {
			removed := sm.CleanExpiredSessions()
			if removed > 0 {
				fmt.Printf("Cleaned %d expired sessions\n", removed)
			}
		}
	}()

	http.HandleFunc("/session/create", sm.handleCreateSession)
	http.HandleFunc("/session/get", sm.handleGetSession)
	http.HandleFunc("/session/update", sm.handleUpdatePreferences)
	http.HandleFunc("/session/delete", sm.handleDeleteSession)

	fmt.Println("Session management server starting on :8080")
	fmt.Println("Endpoints:")
	fmt.Println("  POST /session/create  - Create a new session")
	fmt.Println("  GET  /session/get     - Get current session")
	fmt.Println("  POST /session/update  - Update preferences")
	fmt.Println("  POST /session/delete  - Delete session")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
		os.Exit(1)
	}
}